$location='Adelaide NSW Australia'

# 1) Geocode via Open-Meteo
$geoUrl = 'https://geocoding-api.open-meteo.com/v1/search?name=' + [uri]::EscapeDataString($location) + '&count=1&language=en&format=json'
$geo = Invoke-RestMethod -Uri $geoUrl -Method Get
if (-not $geo.results -or $geo.results.Count -lt 1) { throw "Could not geocode location: $location" }
$r = $geo.results[0]
$lat = [double]$r.latitude
$lon = [double]$r.longitude
$resolved = @($r.name, $r.admin1, $r.country) -ne $null -join ', '

# 2) Forecast
$wxUrl = 'https://api.open-meteo.com/v1/forecast?latitude=' + $lat + '&longitude=' + $lon + '&current=temperature_2m,weathercode,wind_speed_10m&daily=weathercode,temperature_2m_max,temperature_2m_min,precipitation_probability_max&timezone=auto'
$wx = Invoke-RestMethod -Uri $wxUrl -Method Get

function WmoDesc([int]$code) {
  switch ($code) {
    0 {'Clear sky'}
    1 {'Mainly clear'}
    2 {'Partly cloudy'}
    3 {'Overcast'}
    45 {'Fog'}
    48 {'Rime fog'}
    51 {'Light drizzle'}
    53 {'Moderate drizzle'}
    55 {'Dense drizzle'}
    56 {'Light freezing drizzle'}
    57 {'Dense freezing drizzle'}
    61 {'Slight rain'}
    63 {'Moderate rain'}
    65 {'Heavy rain'}
    66 {'Light freezing rain'}
    67 {'Heavy freezing rain'}
    71 {'Slight snow'}
    73 {'Moderate snow'}
    75 {'Heavy snow'}
    77 {'Snow grains'}
    80 {'Slight rain showers'}
    81 {'Moderate rain showers'}
    82 {'Violent rain showers'}
    85 {'Slight snow showers'}
    86 {'Heavy snow showers'}
    95 {'Thunderstorm'}
    96 {'Thunderstorm with slight hail'}
    99 {'Thunderstorm with heavy hail'}
    default {"Weather code $code"}
  }
}

$dates = $wx.daily.time
if (-not $dates -or $dates.Count -lt 2) { throw 'Daily forecast missing.' }

$todayDate = $dates[0]
$tomorrowDate = $dates[1]

$todayCode = [int]$wx.daily.weathercode[0]
$tomCode   = [int]$wx.daily.weathercode[1]

$todayMax = $wx.daily.temperature_2m_max[0]
$todayMin = $wx.daily.temperature_2m_min[0]
$todayPop = $wx.daily.precipitation_probability_max[0]

$tomMax = $wx.daily.temperature_2m_max[1]
$tomMin = $wx.daily.temperature_2m_min[1]
$tomPop = $wx.daily.precipitation_probability_max[1]

$curTemp = $wx.current.temperature_2m
$curWind = $wx.current.wind_speed_10m
$curCode = [int]$wx.current.weathercode

$lines = @()
$lines += "Weather for: $location"
$lines += "Resolved as: $resolved"
$lines += "Timezone: $($wx.timezone)"
$lines += ''
$lines += "CURRENT"
$lines += "- $([DateTime]::Now.ToString('yyyy-MM-dd HH:mm')): $(WmoDesc $curCode), ${curTemp}$($wx.current_units.temperature_2m), wind ${curWind}$($wx.current_units.wind_speed_10m)"
$lines += ''
$lines += "TODAY ($todayDate)"
$lines += "- Outlook: $(WmoDesc $todayCode)"
$lines += "- High/Low: ${todayMax}$($wx.daily_units.temperature_2m_max) / ${todayMin}$($wx.daily_units.temperature_2m_min)"
$lines += "- Precipitation probability (max): ${todayPop}$($wx.daily_units.precipitation_probability_max)"
$lines += ''
$lines += "TOMORROW ($tomorrowDate)"
$lines += "- Outlook: $(WmoDesc $tomCode)"
$lines += "- High/Low: ${tomMax}$($wx.daily_units.temperature_2m_max) / ${tomMin}$($wx.daily_units.temperature_2m_min)"
$lines += "- Precipitation probability (max): ${tomPop}$($wx.daily_units.precipitation_probability_max)"

$outFile = Join-Path $env:TEMP ("weather_{0}.txt" -f (($location -replace '[^A-Za-z0-9]+','_').Trim('_')))
$lines -join "`r`n" | Set-Content -Path $outFile -Encoding UTF8

$outFile

$location='Adelaide NSW Australia'

$stateMap = @{
  'NSW'='New South Wales'
  'VIC'='Victoria'
  'QLD'='Queensland'
  'SA'='South Australia'
  'WA'='Western Australia'
  'TAS'='Tasmania'
  'NT'='Northern Territory'
  'ACT'='Australian Capital Territory'
}

function Geocode([string]$q){
  $u='https://geocoding-api.open-meteo.com/v1/search?name='+[uri]::EscapeDataString($q)+'&count=5&language=en&format=json'
  try { Invoke-RestMethod -Uri $u -Method Get } catch { $null }
}

$geo = Geocode $location
if (-not $geo -or -not $geo.results) {
  # try without common state abbreviations
  $q2 = ($location -split '\s+' | Where-Object { -not $stateMap.ContainsKey($_.ToUpper()) }) -join ' '
  $geo = Geocode $q2
  if (-not $geo -or -not $geo.results) {
    $geo = Geocode (($location -split '\s+')[0])
  }
}
if (-not $geo -or -not $geo.results) { throw "Could not geocode location: $location" }

$wantState = $null
